def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

print(factorial(5))
print(factorial(10))

def fib(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    return fib(n - 1) + fib(n - 2)

print(fib(0))
print(fib(1))
print(fib(7))
print(fib(10))

def max2(a, b):
    if a > b:
        return a
    return b

def max3(a, b, c):
    return max2(max2(a, b), c)

print(max3(3, 7, 5))
print(max3(10, 4, 8))
print(max3(9, 9, 1))
print(max3(1, 1, 1))
